@* Reusable message input with textarea and submit button *@

<div class="message-input">
    <textarea value="@Text" @oninput="OnInput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder" rows="1"></textarea>
    <button @onclick="Submit" disabled="@string.IsNullOrWhiteSpace(Text)">@ButtonText</button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message...";
    [Parameter] public string ButtonText { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSubmit { get; set; }

    private string Text { get; set; } = "";
    private bool _submitting;

    private void OnInput(ChangeEventArgs e)
    {
        if (!_submitting)
            Text = e.Value?.ToString() ?? "";
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            _submitting = true;
            await Submit();
            _submitting = false;
        }
    }

    private async Task Submit()
    {
        if (!string.IsNullOrWhiteSpace(Text))
        {
            var text = Text.Trim();
            Text = "";
            await OnSubmit.InvokeAsync(text);
        }
    }
}

.message-input {
    padding: 12px 20px;
    border-top: 1px solid #383838;
    display: flex;
    gap: 8px;
    align-items: flex-end;
    flex-shrink: 0;
}

.message-input textarea {
    flex: 1;
    background: #2c2d30;
    border: 1px solid #464748;
    border-radius: 8px;
    color: #d1d2d3;
    padding: 10px 14px;
    font-size: 0.9rem;
    resize: none;
    font-family: inherit;
    outline: none;
    min-height: 40px;
    max-height: 120px;
}

.message-input textarea:focus {
    border-color: #1d9bd1;
}

.message-input textarea::placeholder {
    color: #7a7b7e;
}

.message-input button {
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 10px 20px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
}

.message-input button:hover:not(:disabled) {
    background: #148567;
}

.message-input button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.channel-item {
    padding: 6px 20px;
