+<div class="message-area">
+    @if (CurrentChannel != null)
+    {
+        <div class="channel-header">
+            <h2># @CurrentChannel.Name</h2>
+            <p>@CurrentChannel.Description</p>
+        </div>
+
+        <div class="message-list">
+            @if (HasMoreMessages)
+            {
+                <div class="load-more">
+                    <button @onclick="OnLoadMore" disabled="@IsLoading">
+                        @(IsLoading ? "Loading…" : "⬆ Load older messages")
+                    </button>
+                </div>
+            }
+            @foreach (var msg in Messages)
+            {
+                var summary = ThreadSummaries.GetValueOrDefault(msg.Id);
+                <MessageItem Message="msg"
+                             IsThreadStarter="summary != null"
+                             ReplyCount="@(summary?.ReplyCount ?? 0)"
+                             OnOpenThread="OnOpenThread"
+                             OnReact="OnReact" />
+            }
+        </div>
+
+        <MessageInput Placeholder="@($"Message #{CurrentChannel.Name}")"
+                      ButtonText="Send"
+                      OnSubmit="OnSendMessage" />
+    }
+    else
+    {
+        <div class="no-channel">
+            <p>Select a channel to start messaging</p>
+        </div>
+    }
+</div>
+
+@code {
+    [Parameter] public Channel? CurrentChannel { get; set; }
+    [Parameter] public List<Message> Messages { get; set; } = [];
+    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
+    [Parameter] public bool HasMoreMessages { get; set; }
+    [Parameter] public bool IsLoading { get; set; }
+    [Parameter] public EventCallback OnLoadMore { get; set; }
+    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
+    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
+    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
+}
+

