.thread-panel {
    width: 340px;
    min-width: 340px;
    background: #1e2125;
    border-left: 1px solid #383838;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    padding: 12px 16px;
    border-bottom: 1px solid #383838;
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    color: #fff;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    color: #9a9b9e;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

.close-btn:hover {
    background: #383838;
    color: #fff;
}

.thread-root {
    padding: 16px;
    background: #282b30;
    border-bottom: 1px solid #383838;
    flex-shrink: 0;
}

.root-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 4px;
}

.root-header .author,
.reply-header .author {
    font-weight: 700;
    color: #fff;
    font-size: 0.9rem;
}

.root-header .timestamp,
.reply-header .timestamp {
    font-size: 0.7rem;
    color: #7a7b7e;
}

.root-content,
.reply-content {
    color: #d1d2d3;
    font-size: 0.85rem;
    line-height: 1.5;
    word-break: break-word;
}

.thread-divider {
    padding: 8px 16px;
    font-size: 0.75rem;
    color: #7a7b7e;
    border-bottom: 1px solid #383838;
    flex-shrink: 0;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 4px 16px;
}

.thread-message {
    padding: 8px 0;
    border-bottom: 1px solid rgba(56, 56, 56, 0.4);
}

.thread-message:last-child {
    border-bottom: none;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

