arguments.file_text:
@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_9e819752423b4dcb888f8b1893158f48.Services
@inject IChatService ChatService

<PageTitle>Team Chat</PageTitle>

<div class="chat-container">
    <ChannelSidebar Channels="channels"
                    SelectedChannelId="selectedChannel?.Id"
                    OnChannelSelected="SelectChannel" />

    <MessageArea CurrentChannel="selectedChannel"
                 Messages="messages"
                 ThreadSummaries="threadSummaries"
                 HasMoreMessages="hasMoreMessages"
                 IsLoading="isLoading"
                 OnLoadMore="LoadMoreMessages"
                 OnSendMessage="SendMessage"
                 OnOpenThread="OpenThread"
                 OnReact="AddReaction" />

    @if (isThreadOpen)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     ThreadMessages="threadReplies"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? selectedChannel;
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = [];
    private bool hasMoreMessages;
    private bool isLoading;
    private int skip;
    private const int PageSize = 20;

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
            await SelectChannel(channels[0]);
    }

    private async Task SelectChannel(Channel channel)
    {
        selectedChannel = channel;
        skip = 0;
        messages.Clear();
        threadSummaries.Clear();
        CloseThread();

        await ChatService.MarkChannelReadAsync(channel.Id);
        channels = await ChatService.GetChannelsAsync();

        var loaded = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messages = loaded;
        skip = loaded.Count;
        hasMoreMessages = loaded.Count == PageSize;

        await BuildThreadSummaries();
    }

    private async Task LoadMoreMessages()
    {
        if (isLoading || selectedChannel == null) return;
        isLoading = true;

        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, skip, PageSize);
        messages.InsertRange(0, older);
        skip += older.Count;
        hasMoreMessages = older.Count == PageSize;
        isLoading = false;

        await BuildThreadSummaries();
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel == null) return;
